import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './context/AuthContext'; // Adjust the path as needed
import StudentLanding from './compents/StudentLanding';
import ProfessorLanding from './pages/ProfessorLanding';
import AdminLanding from './pages/AdminLanding';
import SecretaryLanding from './pages/SecretaryLanding';
import LoginPage from './pages/LoginPage'; // Your login component

const App = () => {
  const { currentUser } = useAuth(); // Get the current user from the Auth context

  return (
    <Routes>
      {/* If the user is authenticated, redirect to the appropriate landing page */}
      <Route path="/" element={currentUser ? <Navigate to="/landing" /> : <LoginPage />} />
      <Route path="/landing" element={currentUser ? <StudentLanding /> : <Navigate to="/" />} />
      <Route path="/professor" element={currentUser ? <ProfessorLanding /> : <Navigate to="/" />} />
      <Route path="/admin" element={currentUser ? <AdminLanding /> : <Navigate to="/" />} />
      <Route path="/secretary" element={currentUser ? <SecretaryLanding /> : <Navigate to="/" />} />
      {/* Redirect unmatched routes to Login or NotFound */}
      <Route path="*" element={<Navigate to={currentUser ? "/landing" : "/"} />} />
    </Routes>
  );
};

export default App;
